#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=305;
const ll inf=1e17;
ll n,s,dep[N],mx,mxid,tl,tr,num,f[N][25],dep2[N],ww[N],vis[N];
struct node
{
	ll v,w;
};
vector<node> g[N];
void dfs(int u,int fa)
{
	dep2[u]=dep2[fa]+1;
	f[u][0]=fa;
	if(dep[u]>mx)
	{
		mx=dep[u];
		mxid=u;
	}
	for(int i=0;i<g[u].size();i++)
	{
		ll v=g[u][i].v,w=g[u][i].w;
		if(v==fa) continue;
		dep[v]=dep[u]+w;
		dfs(v,u);
		ww[v]=w;
	}
}
void prepare()
{
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j<=n;j++)
		{
			f[j][i]=f[f[j][i-1]][i-1];
		}
	}
}
int lca(int x,int y)
{
	if(dep2[y]<dep2[x]) swap(x,y);
	int k=log2(dep2[y])+1;
	for(int i=k;i>=0;i--)
	{
		if((dep2[y]-(1<<i))>=dep2[x]) y=f[y][i];
	}
	if(x==y) return x;
	for(int i=k;i>=0;i--)
	{
		if(f[x][i]&&f[x][i]!=f[y][i])
		{
			x=f[x][i];
			y=f[y][i];
		}
	}
	return f[x][0];
}
int up(int u,ll x)
{
	ll tmp=0;
	while(u!=tl&&tmp+ww[u]<=x)
	{
		tmp+=ww[u];
		u=f[u][0];
	}
	return u;
}
ll sum;
ll fun(int u,ll x)
{
	for(int i=0;i<g[u].size();i++)
	{
		ll v=g[u][i].v,w=g[u][i].w;
		if(vis[v])
		{
			if(v==f[u][0]) continue;
			sum+=w;
			if(sum>x) return u;
			else return fun(v,x);
		}
	}
}
bool check(int x)
{
	sum=0;
	ll tmp1=fun(tl,x),tmp2=up(tr,x);
	return (dep[tmp2]-dep[tmp1]<=s);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>s;
	for(int i=1;i<n;i++)
	{
		ll x,y,w;
		cin>>x>>y>>w;
		g[x].push_back(node{y,w});
		g[y].push_back(node{x,w});
	}
	dfs(1,0);
	mx=0;
	tl=mxid;
	dep[mxid]=0;
	dfs(mxid,0);
	tr=mxid;
	num=mx;
	ll l=inf,r=num;
	prepare();
	int tmp=tr;
	while(tmp)
	{
//		cout<<tmp<<" ";
		vis[tmp]=1;
		tmp=f[tmp][0];
	}
	for(int i=1;i<=n;i++)
	{
//		cout<<vis[i]<<" ";
		if(!vis[i])
		{
//			cout<<i<<" : "<<lca(i,tr)<<" "<<dep[i]-dep[lca(i,tr)]<<"\n";
			l=min(l,dep[i]-dep[lca(i,tr)]);
		}
	}
//	cout<<"\n"<<tl<<" "<<tr<<" "<<num<<" "<<l<<" "<<r<<endl;
	while(l<=r)
	{
		ll mid=(l+r)/2;
		if(check(mid)) r=mid-1;
		else l=mid+1;
	}
	cout<<l;
	return 0;
}
